const ip = $input.first().json.body.text;

if (!ip) {
  return [{ json: { valid: false, reason: "IP missing" } }];
}

// Basic IPv4 structure check
const ipv4Regex = /^(\d{1,3}\.){3}\d{1,3}$/;

let valid = false;

if (ipv4Regex.test(ip)) {
  const octets = ip.split('.').map(Number);
  valid = octets.every(o => o >= 0 && o <= 255);
}

return [{
  json: {
    ip,
    valid
  }
}];

const ip = $input.first().json.ip;

const privateRanges = [
  /^10\./,
  /^192\.168\./,
  /^172\.(1[6-9]|2[0-9]|3[0-1])\./,
  /^127\./
];

const isPrivate = privateRanges.some(r => r.test(ip));

return [{
  json: {
    ip,
    isPrivate
  }
}];

const data = $json;

// High-risk country list (adjust as needed)
const highRiskCountries = ["RU", "CN", "IR", "KP"];

// Determine severity
const severity = highRiskCountries.includes(data.country)
  ? "🚨 HIGH RISK"
  : "🟢 Normal";

return [{
  json: {
    ip: data.ip,
    country: data.country || "Unknown",
    region: data.region || "Unknown",
    city: data.city || "Unknown",
    isp: data.org || "Unknown",
    asn: data.org?.split(" ")[0] || "N/A",
    severity
  }
}];
